import WidgetKit
import SwiftUI
import AppIntents
import RealityKit

struct TrophyIntent: AppIntent {
    static var title: LocalizedStringResource = "Fitness Trophy"
    @Parameter(title: "Trophy Name") var trophyName: String
}

struct TrophyWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: "TrophyWidget",
            intent: TrophyIntent.self,
            provider: .static
        ) { entry in
            RealityView { content in
                if let model = try? await ModelEntity(named: entry.trophyName) {
                    content.add(model)
                }
            }
        }
    }
}

